t.script:
document.addEventListener('DOMContentLoaded', function() {
    var serviceType = document.getElementById('service_type');
    var containerTypeGroup = document.getElementById('container_type_group');
    var containerQtyGroup = document.getElementById('container_qty_group');

    function toggleContainerFields() {
        if (serviceType.value === 'fcl') {
            containerTypeGroup.style.display = 'block';
            containerQtyGroup.style.display = 'block';
        } else {
            containerTypeGroup.style.display = 'none';
            containerQtyGroup.style.display = 'none';
        }
    }

    serviceType.addEventListener('change', toggleContainerFields);
    toggleContainerFields();
});
